pub(crate) fn flush(&self, guard: &Guard) {
    let bag = self.bag.with_mut(|b| unsafe { &mut *b });

    if !bag.is_empty() {
        self.global().push_bag(bag, guard);
    }

    self.global().collect(guard);
}

